package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP16LoginConContrasenaIncorrectaPlaywrightTest extends BaseTestPlaywright {    @Test    void loginConContrasenaIncorrecta() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']")                .fill("camarero");        page.locator("input[name='password']")                .fill("incorrecta99");        page.locator("button[type='submit']")                .click();        page.waitForLoadState();        assertTrue(                page.locator("input[name='username']").isVisible(),                "El campo Usuario ya no está visible."        );        assertTrue(                page.locator("input[name='password']").isVisible(),                "El campo Contraseña ya no está visible."        );        assertTrue(                page.url().contains("login"),                "El sistema permitió el acceso con una contraseña incorrecta."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP16-login-contrasena-incorrecta.png"))                        .setFullPage(true)        );    }}